features.snippet:
reg [7:0] q;
reg d, clock, aclr;
always @(posedge aclr or posedge clock) begin
  if (aclr) q <= 0;
end
always @(d) begin
  q <= d;
end

parameter lpm_delay = 0;
reg [7:0] q;
integer i;
always @(posedge aclr or posedge clock) begin
  if (aclr) begin
    for (i = 0; i <= lpm_delay; i = i + 1)
      q <= 0;
  end
end

parameter lpm_delay = 0;
reg [7:0] q;
reg d;
always @(d) begin
  if (lpm_delay == 0)
    q <= d;
end
